import { useState, useRef, useCallback, useEffect } from "react";
import { Platform, Alert } from "react-native";
import type {TreeNode, TreeSelectionEvent} from "@lmb-it/kitsconcerto-types";
import type { TreeProps, ITreeViewProps, ITreeItem, clearFunction } from "@lmb-it/kitsconcerto-types";
import { buildTree, markAncestors } from "./utils";
import {useDialog} from "../../_compat";

// Platform-safe prompt/confirm helpers
const platformPrompt = (title: string, defaultValue?: string): Promise<string | null> => {
    if (Platform.OS === "web") {
        return Promise.resolve(window.prompt(title, defaultValue));
    }
    return new Promise((resolve) => {
        if (Platform.OS === "ios") {
            Alert.prompt(title, undefined, [
                { text: "Cancel", onPress: () => resolve(null), style: "cancel" },
                { text: "OK", onPress: (text) => resolve(text || null) },
            ], "plain-text", defaultValue);
        } else {
            // Android: Alert.prompt not available, use simple alert with default value
            Alert.alert(title, `Confirm to add "${defaultValue || "New Item"}"`, [
                { text: "Cancel", onPress: () => resolve(null), style: "cancel" },
                { text: "OK", onPress: () => resolve(defaultValue || title) },
            ]);
        }
    });
};

const platformConfirm = (message: string): Promise<boolean> => {
    if (Platform.OS === "web") {
        return Promise.resolve(window.confirm(message));
    }
    return new Promise((resolve) => {
        Alert.alert("Confirm", message, [
            { text: "Cancel", onPress: () => resolve(false), style: "cancel" },
            { text: "OK", onPress: () => resolve(true) },
        ]);
    });
};

export const useTreeViewController = <T=any,>(props: ITreeViewProps<T>) => {
    const {
        tree: incomingTree,
        beforeAddCategory,
        beforeAddItem,
        beforeDeleteCategory,
        beforeUpdateCategory,
        beforeUpdateItem,
        beforeDeleteItem,
        beforeSortItem,
        onSelectItem,
        onAddCategory,
        onAddItem,
        onDeleteCategory,
        onTreeChange,
        onDeleteItem,
        onUpdateCategory,
        onSortItem,
        onUpdateItem,
        serverSide,
        preselectList,
        checkbox,
        expendableControls,
        isExpended,
        sortable
    } = props;

    const { toast } = useDialog();

    // --- State ---
    const [treeValue, setTreeValue] = useState<TreeNode<ITreeItem<T>>[]>([]);
    const [expandedKeys, setExpandedKeys] = useState<Record<string, boolean>>({});
    const [selectedKeys, setSelectedKeys] = useState<TreeSelectionEvent["value"]>(null);
    const [selectedNode, setSelectedNode] = useState<TreeNode<ITreeItem<T>> | null>(null);
    const [filterValue, setFilterValue] = useState<string>("");

    // --- Refs (Tracking Changes) ---
    const nodesMapping = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const newNodes = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const newItems = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const editedNodes = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const editedItems = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const deletedNodes = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const deletedItems = useRef<Map<string | number, ITreeItem<T>>>(new Map());
    const nodesCategoriesChecked = useRef<(number | string)[]>([]);
    const nodesItemsChecked = useRef<(number | string)[]>([]);
    const nodesCategoriesUnChecked = useRef<(number | string)[]>([]);
    const nodesItemsUnChecked = useRef<(number | string)[]>([]);

    // --- Helpers ---

    const setNodesMapping = (newMap: Map<string | number, ITreeItem<T>>) => {
        nodesMapping.current = newMap;
        setTreeValue(buildTree(nodesMapping.current, !!props.rules?.allowIndependentItem));
    };

    const setNodeState = (newNode: ITreeItem<T>) => {
        nodesMapping.current.set(newNode.value.toString(), newNode);
        setNodesMapping(nodesMapping.current);
    };

    const clear: clearFunction = (specify = "all") => {
        switch (specify) {
            case "checkedCategories": nodesCategoriesChecked.current = []; break;
            case "checkedItems": nodesItemsChecked.current = []; break;
            case "unCheckedCategories": nodesCategoriesUnChecked.current = []; break;
            case "unCheckedItems": nodesItemsUnChecked.current = []; break;
            case "newItems": newItems.current = new Map(); break;
            case "newCategories": newNodes.current = new Map(); break;
            case "editedItems": editedItems.current = new Map(); break;
            case "editedCategories": editedNodes.current = new Map(); break;
            case "deletedItems": deletedItems.current = new Map(); break;
            case "deletedCategories": deletedNodes.current = new Map(); break;
            case "all":
            default:
                nodesCategoriesChecked.current = [];
                nodesItemsChecked.current = [];
                nodesCategoriesUnChecked.current = [];
                nodesItemsUnChecked.current = [];
                newItems.current = new Map();
                newNodes.current = new Map();
                editedItems.current = new Map();
                editedNodes.current = new Map();
                deletedItems.current = new Map();
                deletedNodes.current = new Map();
                break;
        }
    };

    const fireOnChange = () => {
        onTreeChange &&
        onTreeChange(
            {
                checkedCategories: nodesCategoriesChecked.current,
                checkedItems: nodesItemsChecked.current,
                unCheckedCategories: nodesCategoriesUnChecked.current,
                unCheckedItems: nodesItemsUnChecked.current,
                newItems: Array.from(newItems.current.values()),
                newCategories: Array.from(newNodes.current.values()),
                editedItems: Array.from(editedItems.current.values()),
                editedCategories: Array.from(editedNodes.current.values()),
                deletedItems: Array.from(deletedItems.current.values()),
                deletedCategories: Array.from(deletedNodes.current.values()),
            },
            clear,
        );
    };

    const setNodesChecked = (
        checkedCategories: (number | string)[],
        checkedItems: (number | string)[],
        unCheckedCategories: (number | string)[],
        unCheckedItems: (number | string)[],
    ) => {
        nodesCategoriesChecked.current = checkedCategories;
        nodesItemsChecked.current = checkedItems;
        nodesItemsUnChecked.current = unCheckedItems;
        nodesCategoriesUnChecked.current = unCheckedCategories;
        fireOnChange();
    };

    // --- Initialization ---

    // Build Tree Data
    const build = () => {
        if (serverSide?.listFetcher) {
            serverSide.listFetcher().then((res) => {
                if (res.success && res.data) {
                    const mapping: Map<string | number, ITreeItem<T>> = new Map(res.data?.map((item) => [item.value.toString(), item]));
                    setNodesMapping(mapping);
                }
            });
        } else {
            if (incomingTree) {
                const mapping = new Map(incomingTree.map((item) => [item.value.toString(), item]));
                setNodesMapping(mapping);
            }
        }
    };

    // Initial Build
    useEffect(() => {
        build();
    }, [incomingTree]);

    // Preselection Logic (from Selectable.tsx)
    useEffect(() => {
        if (preselectList && nodesMapping.current.size > 0) {
            const ps: TreeSelectionEvent["value"] = {};

            const itemsMap = nodesMapping.current;

            preselectList.forEach((item) => {
                const node = itemsMap.get(item.toString());
                if (node) {
                    ps[item] = { checked: true, partialChecked: false };
                    markAncestors(node.value, itemsMap, ps);
                }
            });
            setSelectedKeys(ps);
        }
    }, [preselectList, treeValue]); // dependency on treeValue to ensure mapping is ready

    // Expansion Logic (from Expendable.tsx)
    const expandNode = (node: TreeNode<ITreeItem<T>>, _expandedKeys: Record<string, boolean>) => {
        if (node.children && node.children.length && node.key) {
            _expandedKeys[node.key] = true;
            for (const child of node.children) {
                expandNode(child, _expandedKeys);
            }
        }
    };

    const expandAll = () => {
        const _expandedKeys: Record<string, boolean> = {};
        for (const node of treeValue) {
            expandNode(node, _expandedKeys);
        }
        setExpandedKeys(_expandedKeys);
    };

    const collapseAll = () => {
        setExpandedKeys({});
    };

    useEffect(() => {
        if (treeValue.length > 0 && isExpended) {
            expandAll();
        }
    }, [treeValue, isExpended]);


    // --- CRUD Operations ---

    const addNode = useCallback(async (
        item: ITreeItem | null = null,
        parentItemValue: string | number | null = null,
        isItem: boolean = false,
    ) => {
        const promptValue = item
            ? item
            : await platformPrompt(
                !isItem
                    ? (props.text?.addNode ?? "Add Category")
                    : (props.text?.addItem ?? "Add Item"),
            );

        if (promptValue) {
            const newNode: ITreeItem =
                typeof promptValue == "object"
                    ? promptValue
                    : {
                        value: promptValue,
                        label: promptValue,
                        parentId: parentItemValue,
                        isItem: isItem,
                        data: {},
                    };

            const func = () => {
                if (isItem) {
                    onAddItem && onAddItem(newNode);
                    newItems.current.set(newNode.value.toString(), newNode);
                } else {
                    onAddCategory && onAddCategory(newNode);
                    newNodes.current.set(newNode.value.toString(), newNode);
                }
                fireOnChange();
            };

            if ((serverSide?.onAddItem && isItem) || (serverSide?.onAddCategory && !isItem)) {
                if (serverSide?.onAddItem && isItem) {
                    serverSide.onAddItem(newNode)?.then((res) => {
                        if(res.success) {
                            setNodeState(newNode);
                            func();
                            build();
                            toast("success", res?.message ?? "Category has been added successfully");
                        }
                    })
                } else if (serverSide?.onAddCategory && !isItem) {
                    serverSide.onAddCategory(newNode)?.then((res) => {
                        if(res.success) {
                            setNodeState(newNode);
                            func();
                            build();
                            toast("success", res.message ?? "Category has been added successfully");
                        }
                    })
                }
            } else {
                setNodeState(newNode);
                func();
            }
        }
    }, [nodesMapping]);

    const deleteNode = useCallback(async (item: ITreeItem, deleted: boolean | null = null) => {
        const promptValue = deleted != null
            ? deleted
            : await platformConfirm(
                item.isItem
                    ? (props.text?.deleteItem ?? "Delete Item")
                    : (props.text?.deleteNode ?? "Delete Category"),
            );

        if (promptValue) {
            const func = () => {
                if (item.isItem) {
                    onDeleteItem && onDeleteItem(item);
                    if (newItems.current.has(item.value.toString())) {
                        newItems.current.delete(item.value.toString());
                    } else {
                        if (editedItems.current.has(item.value.toString())) {
                            editedItems.current.delete(item.value.toString());
                        }
                        deletedItems.current.set(item.value.toString(), item);
                    }
                } else {
                    onDeleteCategory && onDeleteCategory(item);
                    if (newNodes.current.has(item.value.toString())) {
                        newNodes.current.delete(item.value.toString());
                    } else {
                        if (editedNodes.current.has(item.value.toString())) {
                            editedNodes.current.delete(item.value.toString());
                        }
                        deletedNodes.current.set(item.value.toString(), item);
                    }
                }
                fireOnChange();
            };

            if ((serverSide?.onDeleteItem && item.isItem) || (serverSide?.onDeleteCategory && !item.isItem)) {
                if(serverSide?.onDeleteItem && item.isItem) {
                    serverSide.onDeleteItem(item)?.then(res => {
                        if(res.success) {
                            nodesMapping.current.delete(item.value.toString());
                            setNodesMapping(nodesMapping.current);
                            func();
                            build();
                            toast("success", res.message ?? "Item has been deleted successfully");
                        }
                    })
                } else if (serverSide?.onDeleteCategory && !item.isItem) {
                    serverSide.onDeleteCategory(item)?.then(res => {
                        if (res.success) {
                            nodesMapping.current.delete(item.value.toString());
                            setNodesMapping(nodesMapping.current);
                            func();
                            build();
                            toast("success", res.message ?? "Category has been deleted successfully");
                        }
                    })
                }
            } else {
                nodesMapping.current.delete(item.value.toString());
                setNodesMapping(nodesMapping.current);
                func();
            }
        }
    }, [nodesMapping]);

    const updateNode = useCallback(async (item: ITreeItem, updated: boolean = false) => {
        const promptValue = updated
            ? item
            : await platformPrompt(
                !item?.isItem
                    ? (props.text?.editNode ?? "Edit Category")
                    : (props.text?.editItem ?? "Edit Item"),
                item.label,
            );

        if (promptValue) {
            const newNode: ITreeItem = typeof promptValue == "object"
                ? promptValue
                : {
                    value: item.value,
                    label: promptValue,
                    parentId: item.parentId,
                    isItem: !!item?.isItem,
                    data: {},
                };

            const func = () => {
                if (item?.isItem) {
                    onUpdateItem && onUpdateItem(newNode);
                    editedItems.current.set(newNode.value.toString(), newNode);
                } else {
                    onUpdateCategory && onUpdateCategory(newNode);
                    editedNodes.current.set(newNode.value.toString(), newNode);
                }
                fireOnChange();
            };

            if ((serverSide?.onUpdateItem && item?.isItem) || (serverSide?.onUpdateCategory && !item?.isItem)) {
                if(serverSide?.onUpdateItem && item?.isItem) {
                    serverSide.onUpdateItem(newNode)?.then(res => {
                        if(res.success) {
                            setNodeState(newNode);
                            func();
                            build();
                            toast("success", res.message ?? "Item has been updated successfully");
                        }
                    })
                } else if (serverSide?.onUpdateCategory && !item?.isItem) {
                    serverSide.onUpdateCategory(newNode)?.then(res => {
                        if(res.success) {
                            setNodeState(newNode);
                            func();
                            build();
                            toast("success", res.message ?? "Category has been updated successfully");
                        }
                    })
                }
            } else {
                setNodeState(newNode);
                func();
            }
        }
    }, [nodesMapping]);

    // --- Wrapper Functions (Callbacks) ---

    const onAddNode = useCallback((parentItemValue: ITreeItem["value"] | null = null) => {
        if (beforeAddCategory) {
            const findParent = nodesMapping.current.get(parentItemValue?.toString() ?? "") ?? null;
            beforeAddCategory(findParent).then(([added, item]) => {
                if(added) addNode(item);
            });
        } else {
            addNode(null, parentItemValue);
        }
    }, [nodesMapping, addNode]);

    const onAddNodeItem = useCallback((parentItemValue: ITreeItem["value"]) => {
        if (beforeAddItem) {
            const findParent = nodesMapping.current.get(parentItemValue?.toString() ?? "") ?? null;
            beforeAddItem(findParent).then(([added, item]) => {
                if (added) addNode(item, parentItemValue, true);
            })
        } else {
            addNode(null, parentItemValue, true);
        }
    }, [nodesMapping, addNode]);

    const onDeleteNodeWrapper = useCallback((itemValue: ITreeItem["value"]) => {
        const find = nodesMapping.current.get(itemValue.toString());
        if (!find) return;

        if (!find.isItem && beforeDeleteCategory) {
            beforeDeleteCategory(find).then(([deleted]) => {
                if (deleted) deleteNode(find, deleted);
            })
        } else if (find.isItem && beforeDeleteItem) {
            beforeDeleteItem(find).then(([deleted]) => {
                if (deleted) deleteNode(find, deleted);
            })
        } else {
            deleteNode(find);
        }
    }, [nodesMapping, deleteNode]);

    const onEditNodeWrapper = useCallback((itemValue: ITreeItem["value"]) => {
        const find = nodesMapping.current.get(itemValue.toString());
        if (!find) return;

        if (!find.isItem && beforeUpdateCategory) {
            beforeUpdateCategory(find).then(([updated, item]) => {
                if (updated) updateNode(item ?? find, updated);
            })
        } else if (find.isItem && beforeUpdateItem) {
            beforeUpdateItem(find).then(([updated, item]) => {
                if (updated) updateNode(item ?? find, updated);
            })
        } else {
            updateNode(find);
        }
    }, [nodesMapping, updateNode]);


    // --- Event Handlers ---

    const onDragDrop: TreeProps<ITreeItem<T>>["onDragDrop"] = ({ dropNode, dragNode }) => {
        const node = dragNode.data?.data!;
        const toNode: ITreeItem<T> | null = dropNode?.data?.data ? dropNode.data.data : null;
        const newNode = { ...node, parentId: toNode?.value };

        const func = () => {
            onSortItem && onSortItem(node, toNode);
            if (node.isItem) {
                editedItems.current.set(newNode.value.toString(), newNode);
            } else {
                editedNodes.current.set(newNode.value.toString(), newNode);
            }
            fireOnChange();
        };

        const f = () => {
            if (serverSide?.onSortItem) {
                serverSide.onSortItem(node, toNode)?.then(res => {
                    if(res.success) {
                        setNodeState(newNode);
                        func();
                        build();
                        toast("success", res.message ?? "Item has been updated successfully");
                    }
                });
            } else {
                setNodeState(newNode);
                func();
            }
        };

        if (beforeSortItem) {
            beforeSortItem(node, toNode).then(([sort]) => {
                if(sort) f();
            })
        } else {
            f();
        }
    };

    const handleSelectionChange = (e: TreeSelectionEvent) => {
        const v = e.value;
        if (
            v &&
            typeof v == "object" &&
            Object.keys(v).filter((k) => k.includes("uncategorized")).length == 0
        ) {
            const checked = Object.entries(v);
            const categoriesChecked: (number | string)[] = [];
            const itemsChecked: (number | string)[] = [];
            const itemsMap = nodesMapping.current;

            const unchecked = preselectList?.filter(
                (item) => !checked.map(([key]) => key).includes(item.toString())
            ) ?? [];

            const categoriesUnChecked = unchecked.filter((i) => !itemsMap.get(i.toString())?.isItem);
            const itemsUnChecked = unchecked.filter((i) => !!itemsMap.get(i.toString())?.isItem);

            checked.forEach(([key]) => {
                if (itemsMap.get(key.toString())?.isItem) {
                    itemsChecked.push(key);
                } else {
                    categoriesChecked.push(key);
                }
            });

            setNodesChecked(categoriesChecked, itemsChecked, categoriesUnChecked, itemsUnChecked);
            setSelectedKeys(v);
        }
    };

    const onNodeClick: TreeProps<ITreeItem<T>>["onNodeClick"] = (event) => {
        if (event.node.key !== "uncategorized") {
            if (event.node.key == selectedNode?.key) {
                setSelectedNode(null);
            } else {
                onSelectItem?.(event.node);
                setSelectedNode(event.node);
            }
        }
    };

    return {
        // Data
        treeValue,
        selectedNode,
        filterValue,

        // Actions
        build,
        setFilterValue,
        expandAll,
        collapseAll,

        // CRUD Actions
        operations: {
            onAddNode,
            onAddNodeItem,
            onDeleteNode: onDeleteNodeWrapper,
            onEditNode: onEditNodeWrapper,
        },

        // Component Props
        treeProps: {
            value: treeValue,
            expandedKeys: expendableControls || isExpended ? expandedKeys : undefined,
            onToggle: expendableControls || isExpended ? (e: any) => setExpandedKeys(e.value) : undefined,
            selectionMode: (checkbox ? "checkbox" : undefined) as TreeProps['selectionMode'],
            selectionKeys: checkbox ? selectedKeys : undefined,
            onSelectionChange: checkbox ? handleSelectionChange : undefined,
            dragdropScope: sortable ? "demo" : undefined,
            onDragDrop: sortable ? onDragDrop : undefined,
            onNodeClick,
        } as TreeProps<T>
    };
};
